mapper.select:
SELECT u.id as userId, IFNULL(SUM(t.deal_price) / 10000, 0) as totalDealAmount, COUNT(t.id) as totalOrders FROM sys_user u LEFT JOIN tb_transaction t ON u.id = t.sales_id AND t.is_deleted = 0 AND t.status = 4 AND DATE_FORMAT(t.update_time, '%Y-%m') = #{month}
u.id IN
#{id}
GROUP BY u.id
